import { lazy } from "react";

import ViewDefault from "../components/ViewDefault";
import SuspenseCustom from "../components/SuspenseCustom";

const Hero = lazy(() => import("./Home/Hero"));
const Formas = lazy(() => import("./Home/Formas"));
const AdvertisementsOwn = lazy(() => import("./Home/AdvertisementsOwn"));
const Opiniones = lazy(() => import("./Home/Opiniones"));

export default function Home() {
  const sections = [
    { id: "opiniones", label: "Opiniones", content: <Opiniones /> },
    {
      id: "formas",
      label: "Formas",
      content: <Formas />,
    },
    {
      label: "variedades",
      className: "2xl:max-w-[1500px]",
      content: <AdvertisementsOwn />,
    },
  ];

  return (
    <div>
      <SuspenseCustom
        // suspenseFallback={<Skeleton className="w-screen h-[150vh]" />}
        classnames={{
          suspenseFall: "w-screen h-[150vh]",
        }}
      >
        <Hero />
      </SuspenseCustom>

      {sections.map((section) => (
        <ViewDefault
          key={section.label}
          id={section?.id}
          title={section.label}
          className={section?.className || ""}
          disabledInView
        >
          <SuspenseCustom>{section.content}</SuspenseCustom>
        </ViewDefault>
      ))}
    </div>
  );
}
